233 | fun parseInlineMarkdown(text: String): androidx.compose.ui.text.AnnotatedString {
234 |     return buildAnnotatedString {
235 |         val pattern = "(\\*\\*.*?\\*\\*|`.*?`)".toRegex()
236 |         var lastIndex = 0
237 |         
238 |         pattern.findAll(text).forEach { match ->
239 |             append(text.substring(lastIndex, match.range.first))
240 |             val matchText = match.value
241 |             when {
242 |                 matchText.startsWith("**") && matchText.endsWith("**") -> {
243 |                     withStyle(style = SpanStyle(fontWeight = FontWeight.Bold, color = Color.White)) {
244 |                         append(matchText.removeSurrounding("**"))
245 |                     }
246 |                 }
247 |                 matchText.startsWith("`") && matchText.endsWith("`") -> {
248 |                     withStyle(style = SpanStyle(
249 |                         fontFamily = FontFamily.Monospace, 
250 |                         background = Color.Black.copy(alpha = 0.3f), 
251 |                         color = Color(0xFF80CBC4)
252 |                     )) {
253 |                         append(matchText.removeSurrounding("`"))
254 |                     }
255 |                 }
256 |                 else -> append(matchText)
257 |             }
258 |             lastIndex = match.range.last + 1
259 |         }
260 |         append(text.substring(lastIndex))
261 |     }
262 | }
